package main

import (
    "image"
    "image/png"
    "math/cmplx"
    "os"
)

// Mandelbrot - 分形认知扭曲
func mandelbrot(maxIter int) image.Image {
    bounds := image.Rect(int(0), int(0), 800, 600)
    img := image.NewRGBA(bounds)

    for py := 0; py < bounds.Dy(); py++ {
        for px := 0; px < bounds.Dx(); px++ {
            x0 := float64(px)/800*3.5 - 2.5
            y0 := float64(py)/600*2.0 - 1.0
            x, y := 0.0, 0.0
            iter := 0

            for x*x+y*y <= 4 && iter < maxIter {
                xtemp := x*x - y*y + x0
                y = 2*x*y + y0
                x = xtemp
                iter++
            }

            // Persona风格红色调
            img.Set(px, py, color.RGBA{217, 20, 20, 255})
        }
    }
    return img
}

func main() {
    img := mandelbrot(255)
    f, _ := os.Create("mandelbrot.png")
    png.Encode(f, img)
}
